parameters.jsCode:
const contacts = $input.all();
const today = new Date().toISOString().split('T')[0];

let stats = {
  date: today,
  total_in_sequence: 0,
  email_interested: 0,
  email_not_interested: 0,
  email_sequence_complete: 0,
  email_queued: 0,
  unsubscribed: 0
};

for (const item of contacts) {
  const tags = item.json.tags || [];
  stats.total_in_sequence++;
  if (tags.includes('email-interested')) stats.email_interested++;
  if (tags.includes('email-not-interested')) stats.email_not_interested++;
  if (tags.includes('email-sequence-complete')) stats.email_sequence_complete++;
  if (tags.includes('email-sequence-cold')) stats.email_queued++;
  if (tags.includes('unsubscribed')) stats.unsubscribed++;
}

stats.response_rate = stats.total_in_sequence > 0 
  ? ((stats.email_interested + stats.email_not_interested) / stats.total_in_sequence * 100).toFixed(1) + '%'
  : '0%';
stats.positive_rate = stats.total_in_sequence > 0
  ? (stats.email_interested / stats.total_in_sequence * 100).toFixed(1) + '%'
  : '0%';

return [{ json: stats }];

